	let pt = this._props[property] || console.warn("Not tracking " + property + " velocity."),
		val, dif, rotationCap;
	val = parseFloat(skipRecentTick ? pt.v1 : pt.g(pt.t, pt.p));
	dif = (val - parseFloat(pt.v2));
