const parseDate = (cfg) => {
  const { date, utc } = cfg
  if (date === null) return new Date(NaN) // null is invalid
  if (Utils.u(date)) return new Date() // today
  if (date instanceof Date) return new Date(date)
  if (typeof date === 'string' && !/Z$/i.test(date)) {
    const d = date.match(C.REGEX_PARSE)
    if (d) {
      const m = d[2] - 1 || 0
      const ms = (d[7] || '0').substring(0, 3)
      if (utc) {
        return new Date(Date.UTC(d[1], m, d[3]
          || 1, d[4] || 0, d[5] || 0, d[6] || 0, ms))
      }
      return new Date(d[1], m, d[3]
        || 1, d[4] || 0, d[5] || 0, d[6] || 0, ms)
    }
  }

  return new Date(date) // everything else
}

export const composeColorValue = (tween, progress, precision) => {
  const mod = tween._modifier;
  const fn = tween._fromNumbers;
  const tn = tween._toNumbers;
  const r = round(clamp(/** @type {Number} */(mod(lerp(fn[0], tn[0], progress))), 0, 255), 0);
  const g = round(clamp(/** @type {Number} */(mod(lerp(fn[1], tn[1], progress))), 0, 255), 0);
  const b = round(clamp(/** @type {Number} */(mod(lerp(fn[2], tn[2], progress))), 0, 255), 0);
  const a = clamp(/** @type {Number} */(mod(round(lerp(fn[3], tn[3], progress), precision))), 0, 1);
  if (tween._composition !== compositionTypes.none) {
    const ns = tween._numbers;
    ns[0] = r;
    ns[1] = g;
    ns[2] = b;
    ns[3] = a;
  }
  return `rgba(${r},${g},${b},${a})`;
}

export const composeComplexValue = (tween, progress, precision) => {
  const mod = tween._modifier;
  const fn = tween._fromNumbers;
  const tn = tween._toNumbers;
  const ts = tween._strings;
  const hasComposition = tween._composition !== compositionTypes.none;
  let v = ts[0];
  for (let j = 0, l = tn.length; j < l; j++) {
    const n = /** @type {Number} */(mod(round(lerp(fn[j], tn[j], progress), precision)));
    const s = ts[j + 1];
    v += `${s ? n + s : n}`;
    if (hasComposition) {
      tween._numbers[j] = n;
    }
  }
  return v;
}

solve(time) {
  const { zeta, w0, wd, b } = this;
  let t = time;
  if (zeta < 1) {
    // Underdamped
    t = exp(-t * zeta * w0) * (1 * cos(wd * t) + b * sin(wd * t));
  } else if (zeta === 1) {
    // Critically damped
    t = (1 + b * t) * exp(-t * w0);
  } else {
    // Overdamped
    // Using exponential instead of cosh and sinh functions to prevent Infinity
    // Original exp(-zeta * w0 * t) * (cosh(wd * t) + b * sinh(wd * t))
    t = ((1 + b) * exp((-zeta * w0 + wd) * t) + (1 - b) * exp((-zeta * w0 - wd) * t)) / 2;
  }
  return 1 - t;
}

function run(codeList) {
  let result = [], fileIdx = 0
  try {
    codeList.forEach((code, idx) => {
      fileIdx = idx
      if (!tokenize) {
        result = acorn.parse(code, options)
        options.program = result
      } else {
        let tokenizer = acorn.tokenizer(code, options), token
        do {
          token = tokenizer.getToken()
          result.push(token)
        } while (token.type !== acorn.tokTypes.eof)
      }
    })
  } catch (e) {
    console.error(fileMode ? e.message.replace(/\(\d+:\d+\)$/, m => m.slice(0, 1) + inputFilePaths[fileIdx] + " " + m.slice(1)) : e.message)
    process.exit(1)
  }
  if (!silent) console.log(JSON.stringify(result, (_, value) => typeof value === "bigint" ? null : value, compact ? null : 2))
}

function scrollSpyFix($page, $nav) {
    // move everything into one big ul (for Bootstrap scroll-spy)
    var $ul = $nav.children('ul');
    $ul.addClass('nav').addClass('methods');
    $ul.find('.methods').each(function() {
        var $methodsList = $(this);
        var $methods = $methodsList.find('[data-type="method"]');
        var $parentLi = $methodsList.parent();

        $methodsList.remove();
        $methods.remove();
        $parentLi.after($methods);
        $parentLi.addClass('toc-header');

    });

    $page.find('[data-type="method"]').addClass("toc-method");

    $page.find('[id^="."]').each(function() {
        var $ele = $(this);
        var id = $(this).attr('id');
        $ele.attr('id', id.replace('.', ''));
    });
}

function printFlowEnumBody(path, options, print) {
  const { node } = path;
  return [
    node.explicitType ? `of ${node.explicitType} ` : "",
    printObject(path, options, print),
  ];
}

function printLegacyFlowEnumBody(path, options, print) {
  const { node } = path;
  return [
    node.type === "EnumSymbolBody" || node.explicitType
      ? `of ${node.type
          .slice(
            // `Enum`
            4,
            // `Body`
            -4,
          )
          .toLowerCase()} `
      : "",
    printObject(path, options, print),
  ];
}
